// Script Continued Below
var TaskerBannerFilters = Class.create();
TaskerBannerFilters.prototype = {
    initialize: function() {
		this.max = 5;
		this.label = '';
		this.table = '';
		this.filter = '';
		this.orderDesc = '';
		this.orderAsc = '';
		this.idField = '';
		this.displayFieldName = '';
		this.displayFieldName2 = '';
		this.linkView = '';
		this.pageId = '';
		this.viewAllLinkTitle = '';
		this.viewAllLinkPageId = '';
		this.viewAllLinkView = '';
		this.viewAllLinkFilter = '';
		// return values
		var items;
		var record_watchers;
		this.count = 0;
    },

	loadBannerCounts: function(bannerHeaderMenu, OUsWhereIamAMemberAdmin, OUsWhereIamAMember){
		taskerFilters = [];

		// get filter from filters table
		// STRY0101803 - had to change to glide record as some users couldn't see the Table field
		var gr_filters = new GlideRecord('x_153465_discovert_tasker_filters');
		gr_filters.addQuery('u_active', true);
		gr_filters.addQuery('u_filter_menu_header', bannerHeaderMenu);
		gr_filters.orderBy('u_order');
		gr_filters.orderBy('u_filter_label');
		gr_filters.query();

		while (gr_filters.next()) {
			var currentFilter = gr_filters.getDisplayValue('u_filter');
// TODO - check when finished if this was used
			if (currentFilter.indexOf("OUsWhereIamAMemberAdmin") > 0) {
				currentFilter = currentFilter.replace("OUsWhereIamAMemberAdmin", OUsWhereIamAMemberAdmin);
			}
			if (currentFilter.indexOf("OUsWhereIamAMember") > 0) {
				currentFilter = currentFilter.replace("OUsWhereIamAMember", OUsWhereIamAMember);
			}
			// This could be useful for future if we want to do left side one at a time, but otherwise should be removed
			var DiscoverControllerURL = gr_filters.getValue('u_discover_controller_url');
			DiscoverControllerURL = DiscoverControllerURL != null ? (DiscoverControllerURL == true) : false;

			var filter = {
				filter: currentFilter,
				table: gr_filters.getDisplayValue('u_table.name'),
				// These fields are not used unless we provide main list view and bifold options
				field_list: gr_filters.getDisplayValue('u_field_list') + '',
				modal_title_fields: gr_filters.getDisplayValue('u_modal_title_fields') + '',
				modal_title_field_separator: gr_filters.getDisplayValue('u_modal_title_field_separator') + '',
				hoverField: gr_filters.getDisplayValue('u_hover_field') + '',
				filter_label: gr_filters.getDisplayValue('u_filter_label'),
				view_all_page: gr_filters.getDisplayValue('u_view_all_page'),
				// STRY0101803
				// 2.7.0 | 08.06.2021 | mmcc | STRY0106157 - PPM – Modern Portal – New Filter Design
				// include_comments: gr_filters.getDisplayValue('u_include_comments'),
				include_comments: gr_filters.getValue('u_include_comments'),
				// STRY0108629
				DiscoverControllerURL: DiscoverControllerURL,
				o: gr_filters.getDisplayValue('u_order_by'),
				d: gr_filters.getDisplayValue('u_direction'),

				// this label for menu item
				label:gr_filters.getDisplayValue('u_filter_label'),
				// set the menu item type to link
				type:"link",
				// set the link title
				title:gr_filters.getDisplayValue('u_filter_label'),
				// needed in menu template
				items:[],
				href: '?id=' + gr_filters.u_banner_list_page_id + 
					'&view=' + gr_filters.u_banner_list_view_name + 
				'&table=' + gr_filters.getDisplayValue('u_table.name') + '&filter=' + currentFilter + '&label=' + gr_filters.getDisplayValue('u_filter_label')
			};
			// custom fitler is retured if one exists, otherwise, same filter is returned
			filter.filter = this._getCustomFilter(filter.filter, filter.title);
			filter.isBannerItem = true;
			var count = new GlideAggregate(filter.table);
			count.addEncodedQuery(filter.filter);
			count.addAggregate('COUNT');
			count.query();
			if (count.next()) {
				filter.count = count.getAggregate('COUNT');
			}
			// NOTE - always add the filter and the record watcher
			//        HTML will only sho if (!isBannerItem || (isBannerItem && count>0)
			this.items.push(filter);
			// NOTE - record watcher needs to do 2 things
			//        1. show and hide the item and the whole banner if only item shown
			//        2. update the indicator when the count increases to tell the user there is an update since last open
			this.record_watchers.push({'table':filter.table,'filter': filter.filter});							
		}
	},

	_getCustomFilter: function(filter, fitlerName){
		switch (fitlerName){
			case "Acceptance Overdue":
				filter = this._getFilterAcceptanceOverdue();
				break;
			case "Awaiting Assignment":
				filter = this._getFilterAwaitingAssignment();
				break;
			case "Awaiting Assignment Overdue":
				filter = this._getFilterAwaitingAssignmentOverdue();
				break;
			case "Awaiting OU Reassignment":
				filter = this._getFilterAwaitingOUReassignment();
				break;				
		}
		return filter;
	},

	// TODO - revisit and see how many of these functions can be combined and improved
	_getFilterAcceptanceOverdue: function(){
		var fitler;
		var u = gs.getUser().getID();
		var daysBeforeTaskAcceptanceIsOverdue = gs.getProperty("x_153465_discovert.#DaysBeforeTaskAcceptanceIsOverdue");
		var isGTA = gs.getUser().hasRole("x_153465_discovert.tasker_global_Tasking_Authority_member_admin");

		// STRY0102134 - Apply Default Schedule to Task Information
		var tdc = new TaskerDurationCalculator();
		var today = new GlideDateTime().getDate();

		// find the end date in the schedule
		var dayInSchedule = tdc.calculateDateOfAddedBusinessDays(null, daysBeforeTaskAcceptanceIsOverdue, today);

		//------------------------------------------------------------------------------------------------------------------
		// Build the Filter using Task Manger OUs, OUs where member and GTA if they are in that role
		// Get the list of OUs where the current user is a Task Manager
		var primary_assigneeFilter = "primary_assigneeIN";
		var taskSystemSettings = new tasking_System_Settings_Scripts();
		// DFCT0010669
		var aMyOUTaskManager = taskSystemSettings.getMyOUTaskManagers();

		// DFCT0010826 - only load items for offices where there is no task manager
		var aOUsWithNoTaskManager = taskSystemSettings.getOUsWithNoTaskManager();


		// DFCT0010826 - state did not have ^, so no tasks were returned for task manager.  Assigned to was added so users see where they are overdue also
		filter = "primary_assigneeIN" + aMyOUTaskManager.join(",") + "^state=1^suspense_dateISNOTEMPTY^suspense_date<="+ dayInSchedule +
			"^NQassigned_to=" + u + "^state=1^suspense_dateISNOTEMPTY^suspense_date<="+ dayInSchedule;
		if(isGTA){
			// DFCT0010826 - changed to only load items for offices where there is no task manager
			filter = "primary_assigneeIN" + aOUsWithNoTaskManager.join(",") + "^state=1^suspense_dateISNOTEMPTY^suspense_date<="+ dayInSchedule;
		}	
		var aOUSchedules = tdc.getOUsWithScheduleOverride(aMyOUTaskManager);

		if(aOUSchedules.length > 0) {
			for (i=0; i<aOUSchedules.length; i++) {
				var grOU = new GlideRecord('x_153465_discovert_discover_office_hierarchy');
				if(grOU.get(aOUSchedules[i].ouId)){
					var overrideDayInSchedule = tdc.calculateDateOfAddedBusinessDays(grOU, daysBeforeTaskAcceptanceIsOverdue, today);
					filter += '^NQprimary_assignee=' + aOUSchedules[i].ouId + '^state=1^suspense_dateISNOTEMPTY^suspense_date<='+overrideDayInSchedule;
				}
			}
		}
		return filter;
	},

	// TODO - revisit and see how many of these functions can be combined and improved
	_getFilterAwaitingAssignment: function(){
		var u = gs.getUser().getID();
		//------------------------------------------------------------------------------------------------------------------
		// Build the Filter using Task Manger OUs, OUs where member and GTA if they are in that role
		// Get the list of OUs where the current user is a Task Manager
		var primary_assigneeFilter = "primary_assigneeIN";
		var taskSystemSettings = new tasking_System_Settings_Scripts();
		// DFCT0010669 
		primary_assigneeFilter += taskSystemSettings.getMyOUTaskManagers().join(",");
		// Get the list of OUs where the current user is a Member
		var primary_assigneeMemberFilter = "primary_assigneeIN";
		// DFCT0010669 
		primary_assigneeMemberFilter +=   taskSystemSettings.getOUsWhereIamAMember().join(",");

		var filter = 'stateIN-5,11^' + primary_assigneeFilter;
		var filterMember = 'stateIN-5,11^' + primary_assigneeMemberFilter + '^primary_assignee.tasking_authoritiesISEMPTY';
		filter = filter + '^NQ' + filterMember;
		var isGTA = gs.getUser().hasRole("x_153465_discovert.tasker_global_Tasking_Authority_member_admin");
		if(isGTA){
			var filterGTA = 'stateIN-5,11^primary_assigneeISNOTEMPTY^primary_assignee.tasking_authoritiesISEMPTY';
			filter = filter + '^NQ' + filterGTA;
		}
		return filter;
	},

	// TODO - revisit and see how many of these functions can be combined and improved
	_getFilterAwaitingAssignmentOverdue: function(){
		var u = gs.getUser().getID();
		var DaysSinceTaskWasUnassignedOrRejectedWarning = gs.getProperty("x_153465_discovert.#DaysSinceTaskWasUnassignedOrRejectedWarning");
		// DFCT0010833 -  change to negative to subtract days instead of adding days to today.
		if(parseInt(DaysSinceTaskWasUnassignedOrRejectedWarning)>0){
			DaysSinceTaskWasUnassignedOrRejectedWarning = 0 - DaysSinceTaskWasUnassignedOrRejectedWarning;
		}
		var isGTA = gs.getUser().hasRole("x_153465_discovert.tasker_global_Tasking_Authority_member_admin");

		// STRY0102134 - Apply Default Schedule to Task Information
		var tdc = new TaskerDurationCalculator();
		var today = new GlideDateTime();

		// find the end date in the schedule
		var dayInSchedule = tdc.calculateDateOfAddedBusinessDays(null, DaysSinceTaskWasUnassignedOrRejectedWarning, today);
		//------------------------------------------------------------------------------------------------------------------
		// Build the Filter using Task Manger OUs, OUs where member and GTA if they are in that role
		// Get the list of OUs where the current user is a Task Manager
		var taskSystemSettings = new tasking_System_Settings_Scripts();
		// DFCT0010669
		var aMyOUTaskManager = taskSystemSettings.getMyOUTaskManagers();

		var filter = "primary_assigneeIN" + aMyOUTaskManager.join(",") + '^primary_assignee.u_schedule_overrideISEMPTY^u_last_unassigned_dateISNOTEMPTY^state=-5^ORstate=11^u_last_unassigned_date<='+dayInSchedule;

		if(isGTA){
			// load all items and use the sytem wide default for the delay days
			filter = 'u_last_unassigned_dateISNOTEMPTY^state=-5^ORstate=11^u_last_unassigned_date<='+dayInSchedule;
		}

		var aOUSchedules = tdc.getOUsWithScheduleOverride(aMyOUTaskManager);

		if(aOUSchedules.length > 0) {
			for (i=0; i<aOUSchedules.length; i++) {
				var grOU = new GlideRecord('x_153465_discovert_discover_office_hierarchy');
				if(grOU.get(aOUSchedules[i].ouId)){
					var overrideDayInSchedule = tdc.calculateDateOfAddedBusinessDays(grOU, DaysSinceTaskWasUnassignedOrRejectedWarning, today);
					filter += '^NQprimary_assignee=' + aOUSchedules[i].ouId + '^u_last_unassigned_dateISNOTEMPTY^state=-5^ORstate=11^u_last_unassigned_date<='+overrideDayInSchedule;
				}
			}
		}

		return filter;
	},

	// TODO - revisit and see how many of these functions can be combined and improved
	_getFilterAwaitingOUReassignment: function(){
		var u = gs.getUser().getID();
		var filter = 'active=true^state=11^primary_assigneeISEMPTY';
		if(!gs.hasRole("x_153465_discovert.tasker_global_Tasking_Authority_member_admin")){
			filter += '^state=11^primary_assigneeISEMPTY^u_task_requesterDYNAMIC90d1921e5f510100a9ad2572f2b477fe^active=true'; 
		}

		return filter;
	},

	createBanner: function(){
		this.record_watchers = [];
		this.record_watchers.push({'table':this.table,'filter': this.filter});

		// DFCT0010669
		var oUserPref = new x_153465_discovert.tasker_User_Form_Preferences();
		var userPreferences = oUserPref.loadMyFormPreferences();

		// get the total count for the banner
		var ga = new GlideAggregate(this.table);
		ga.addEncodedQuery(this.filter);
		ga.addAggregate("COUNT");

		ga.query();
		if(ga.next()){
			this.count = ga.getAggregate("COUNT");
		}

		var gr = new GlideRecord(this.table);
		gr.addActiveQuery();
		gr.addEncodedQuery(this.filter);
		if(this.orderAsc != ''){
			gr.orderBy(this.orderAsc);	
		} else if (this.orderDesc != ''){
			gr.orderByDesc(this.orderDesc);
		}
		gr.setLimit(this.max);
		gr.query();
		this.items = [];
		while (gr.next()) {
			var pageId = this.pageId;
			var view = this.linkView;

			// if just getting the URL, then get URL and return
			if(this.table=='x_153465_discovert_route_task_instance'){
				var url_Properties = oUserPref.get_URL_Properties_for_Task_Based_on_Prefrences(gr.getUniqueValue(), this.linkView);
				pageId = url_Properties.pageId && url_Properties.pageId != '' ? url_Properties.pageId : this.pageId;
				view = url_Properties.view && url_Properties.view != '' ? url_Properties.view : this.linkView;
			}


			if (!gr.canRead())
				continue;
			var title = '';
			if(this.displayFieldName2 !=''){
				title = gr.getValue(this.displayFieldName) + ": " + gr.getValue(this.displayFieldName2); 
			}else{
				title = gr.getValue(this.displayFieldName); 
			}
			this.items.push({
				title: title ,
				type: 'link',
				href: '?' + this.idField + '='+ gr.getValue(this.idField) + '&view=' + view + '&id=' + pageId + '&table=' + this.table
			}); 			
		}

		var link = {title: gs.getMessage(this.viewAllLinkTitle), type: 'link', href: '?id=' + this.viewAllLinkPageId + '&view=' + this.viewAllLinkView + '&table=' + this.table + '&filter=' + this.viewAllLinkFilter + '&label=' + this.label, items: []};
		this.items.push(link); 
	},

	getUserPreferences: function(){
		// get the Offices where a User is the Task Manager as a list for filters
		var preferenceName = 'DTechApps.Tasker.AccessAcknowledgement';
		var preferenceDescription = preferenceName;

		var gdt = new GlideDateTime();
		data.today = gdt.getLocalDate().getDisplayValue();
		data.newPreference = data.today;
		data.currentpreference = gs.getUser().getPreference(preferenceName);   

		if (input && input.answer) {
			var answer = input.answer;

			if (input.answer == true) {
				gs.getUser().savePreference(preferenceName, data.newPreference);
			} 
		}
	},
    type: 'TaskerBannerFilters'
};
